        val taskType = intent.getStringExtra(EXTRA_TASK_TYPE)
        if (taskType.isNullOrBlank() || taskType !in ALLOWED_TASK_TYPES) {
            Log.w(TAG, "Invalid or missing task type: $taskType")
            return null
        }

        // Validate task ID (required, alphanumeric + hyphens/underscores only)
