        if (taskId.isNullOrBlank() || taskId.length > MAX_TASK_ID_LENGTH) {
            Log.w(TAG, "Invalid or missing task ID")
            return null
        }
        if (!taskId.matches(Regex("^[a-zA-Z0-9_-]+$"))) {
            Log.w(TAG, "Task ID contains invalid characters: $taskId")
            return null
        }

        // Validate priority (optional, bounded)
        val rawPriority = intent.getIntExtra(EXTRA_TASK_PRIORITY, DEFAULT_PRIORITY)
        val priority = rawPriority.coerceIn(MIN_PRIORITY, MAX_PRIORITY)

        // Build validated params based on task type
        val params = mutableMapOf<String, Any>()

        when (taskType) {
            TASK_TYPE_SYNC -> {
                val syncTarget = intent.getStringExtra(EXTRA_SYNC_TARGET)
                if (syncTarget.isNullOrBlank() || syncTarget !in ALLOWED_SYNC_TARGETS) {
                    Log.w(TAG, "Invalid or missing sync target: $syncTarget")
                    return null
                }
                if (syncTarget.length > MAX_SYNC_TARGET_LENGTH) {
                    Log.w(TAG, "Sync target exceeds max length")
                    return null
                }
                params["syncTarget"] = syncTarget
            }
            TASK_TYPE_CLEANUP -> {
                val olderThanDays = intent.getIntExtra(EXTRA_CLEANUP_OLDER_THAN_DAYS, 30)
                val validatedDays = olderThanDays.coerceIn(MIN_CLEANUP_DAYS, MAX_CLEANUP_DAYS)
                params["olderThanDays"] = validatedDays
