            TASK_TYPE_CACHE_CLEAR, TASK_TYPE_DB_OPTIMIZE -> {
                // No additional parameters needed; ignore any extras
            }
        }

        // Reject intents with data URIs to prevent URI-based attacks
        if (intent.data != null) {
            Log.w(TAG, "Intent contains unexpected data URI, rejecting")
            return null
        }

        // Reject intents with clip data
        if (intent.clipData != null) {
            Log.w(TAG, "Intent contains unexpected clip data, rejecting")
            return null
        }

        return TaskInfo(
            taskId = taskId,
            taskType = taskType,
            priority = priority,
            callerPackage = callerPackage,
            params = params
        )
    }

