        Log.i(TAG, "Starting data sync for target: $syncTarget, task: ${taskInfo.taskId}")

        return try {
            // Simulate sync work
            Thread.sleep(2000)

            when (syncTarget) {
                "contacts" -> syncContacts()
                "calendar" -> syncCalendar()
                "settings" -> syncSettings()
                "app_data" -> syncAppData()
                "preferences" -> syncPreferences()
                else -> return TaskResult.Failure(taskInfo.taskId, "Unsupported sync target")
            }

            TaskResult.Success(taskInfo.taskId, "Sync completed for $syncTarget")
        } catch (e: InterruptedException) {
            Thread.currentThread().interrupt()
            TaskResult.Failure(taskInfo.taskId, "Sync interrupted")
        } catch (e: Exception) {
            Log.e(TAG, "Sync failed for ${taskInfo.taskId}", e)
            TaskResult.Failure(taskInfo.taskId, "Sync failed: ${e.message}")
        }
    }

    private fun performCleanup(taskInfo: TaskInfo): TaskResult {
