    private fun cleanupOldLogs(olderThanDays: Int) {
        Log.d(TAG, "Cleaning up logs older than $olderThanDays days")
        val logsDir = java.io.File(filesDir, "logs")
        if (logsDir.exists()) {
            val cutoffTime = System.currentTimeMillis() - (olderThanDays * 24L * 60 * 60 * 1000)
            logsDir.listFiles()?.forEach { file ->
                if (file.isFile && file.lastModified() < cutoffTime) {
                    file.delete()
                }
            }
        }
    }

    private fun cleanupTempFiles(olderThanDays: Int) {
